function safeJsonParse(s) {
  try {
    return JSON.parse(s);
  } catch {
    return null;
  }
}

function nowIso() {
  return new Date().toISOString();
}

function httpRequestJson(urlStr, { method = "POST", headers = {}, body, timeoutMs = 4000 } = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlStr);
    const payload = body == null ? null : Buffer.from(JSON.stringify(body));
    const req = https.request(
      {
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === "https:" ? 443 : 80),
        path: url.pathname + url.search,
        method,
        headers: {
          "content-type": "application/json",
          ...(payload ? { "content-length": String(payload.length) } : {}),
          ...headers,
        },
        timeout: timeoutMs,
      },
      (res) => {
        let data = "";
        res.setEncoding("utf8");
        res.on("data", (chunk) => (data += chunk));
        res.on("end", () => {
          const json = safeJsonParse(data);
          resolve({
            statusCode: res.statusCode || 0,
            headers: res.headers,
            bodyText: data,
            bodyJson: json,
          });
        });
      }
    );
    req.on("timeout", () => {
      req.destroy(new Error("HTTP timeout"));
    });
    req.on("error", reject);
    if (payload) req.write(payload);
    req.end();
  });
}

async function updateOrder(orderId, update) {
  // Simple approach: store a processing record via Put or Update with SET.
  // Use UpdateItem with a flexible map attribute "payment" and status fields.
  const expr = [];
  const names = {};
  const values = {};

  function setAttr(path, value) {
    const parts = path.split(".");
    const nameTokens = parts.map((p, i) => {
      const t = `#n${Object.keys(names).length}_${i}`;
      names[t] = p;
      return t;
    });
    const valueToken = `:v${Object.keys(values).length}`;
    values[valueToken] = value;
    expr.push(`${nameTokens.join(".")} = ${valueToken}`);
  }

  setAttr("updatedAt", nowIso());

  for (const [k, v] of Object.entries(update || {})) {
    if (k.includes(".")) setAttr(k, v);
    else setAttr(k, v);
  }

  const cmd = new UpdateItemCommand({
    TableName: ORDERS_TABLE,
    Key: marshall({ orderId }),
    UpdateExpression: "SET " + expr.join(", "),
    ExpressionAttributeNames: names,
    ExpressionAttributeValues: marshall(values, { removeUndefinedValues: true }),
  });

  await ddb.send(cmd);
}

async function markAttempt(orderId, attempt) {
  try {
    await updateOrder(orderId, {
      "processing.lastAttemptAt": nowIso(),
      "processing.lastAttemptId": attempt.attemptId,
      "processing.lastError": attempt.lastError || null,
      "processing.lastPaymentStatus": attempt.paymentStatus || null,
    });
  } catch (e) {
    console.error("DDB markAttempt error", { orderId, error: String(e) });
  }
}

async function callPaymentApi(order) {
  const headers = {
    [IDP_KEY_HEADER]: PAYMENT_API_KEY ? `Bearer ${PAYMENT_API_KEY}` : undefined,
    [PAYMENT_IDEMPOTENCY_HEADER]: order.idempotencyKey || order.orderId,
  };
  Object.keys(headers).forEach((k) => headers[k] == null && delete headers[k]);

  const resp = await httpRequestJson(
    PAYMENT_API_URL,
    {
      method: "POST",
      headers,
      body: {
        orderId: order.orderId,
        amount: order.amount,
        currency: order.currency,
        customerId: order.customerId,
        paymentMethod: order.paymentMethod,
        metadata: order.metadata || {},
      },
      timeoutMs: Number(HTTP_TIMEOUT_MS) || 4000,
    }
  );

  return resp;
}

async function processOneRecord(record) {
  const receiptHandle = record.receiptHandle;
  const messageId = record.messageId;

  const body = typeof record.body === "string" ? safeJsonParse(record.body) : record.body;
  if (!body || !body.orderId) {
    console.error("Invalid message body", { messageId, body: record.body });
    return { receiptHandle, ok: true, delete: true };
  }

  const order = {
    orderId: String(body.orderId),
    amount: body.amount,
    currency: body.currency || "USD",
    customerId: body.customerId,
    paymentMethod: body.paymentMethod,
    metadata: body.metadata,
    idempotencyKey: body.idempotencyKey,
  };

  const attemptId = `${messageId}-${Date.now()}`;
  await markAttempt(order.orderId, { attemptId });

  try {
    const payResp = await callPaymentApi(order);

    if (payResp.statusCode >= 200 && payResp.statusCode < 300) {
      const payment = payResp.bodyJson || {};
      try {
        await updateOrder(order.orderId, {
          status: "PAID",
          "payment.status": "PAID",
          "payment.paymentId": payment.paymentId || payment.id || null,
          "payment.providerStatusCode": payResp.statusCode,
          "payment.raw": payment,
        });
      } catch (e) {
        console.error("DDB update paid error", { orderId: order.orderId, error: String(e) });
      }
      return { receiptHandle, ok: true, delete: true };
    }

    console.error("Payment API non-2xx", {
      orderId: order.orderId,
      statusCode: payResp.statusCode,
      body: payResp.bodyText,
    });

    await markAttempt(order.orderId, {
      attemptId,
      lastError: `Payment API non-2xx: ${payResp.statusCode}`,
      paymentStatus: "FAILED",
    });

    // Let SQS/Lambda retry by not deleting message
    return { receiptHandle, ok: false, delete: false };
  } catch (e) {
    console.error("Payment API error", { orderId: order.orderId, error: String(e) });
    await markAttempt(order.orderId, {
      attemptId,
      lastError: String(e),
      paymentStatus: "ERROR",
    });
    // Let SQS/Lambda retry by not deleting message
    return { receiptHandle, ok: false, delete: false };
  }
}

async function deleteBatch(queueUrl, handles) {
  if (!queueUrl || !handles.length) return;
  const Entries = handles.map((h, i) => ({ Id: String(i), ReceiptHandle: h }));
  try {
    const resp = await sqs.send(new DeleteMessageBatchCommand({ QueueUrl: queueUrl, Entries }));
    if (resp.Failed && resp.Failed.length) {
      console.error("DeleteMessageBatch failed items", resp.Failed);
    }
  } catch (e) {
    console.error("DeleteMessageBatch error", String(e));
  }
}

async function runWithConcurrency(items, concurrency, worker) {
  const results = new Array(items.length);
  let idx = 0;

  async function run() {
    for (;;) {
      const i = idx++;
      if (i >= items.length) return;
      try {
        results[i] = await worker(items[i], i);
      } catch (e) {
        console.error("Worker error", String(e));
        results[i] = null;
      }
    }
  }

  const n = Math.max(1, Math.min(concurrency, items.length || 1));
  const runners = [];
  for (let i = 0; i < n; i++) runners.push(run());
  await Promise.all(runners);
  return results;
}

exports.handler = async (event) => {
  const records = Array.isArray(event.Records) ? event.Records : [];
  if (!ORDERS_TABLE) console.error("Missing env ORDERS_TABLE");
  if (!PAYMENT_API_URL) console.error("Missing env PAYMENT_API_URL");
  if (!QUEUE_URL) console.error("Missing env QUEUE_URL");

  const concurrency = Math.max(1, Number(MAX_CONCURRENCY) || 10);

  const perRecord = await runWithConcurrency(records, concurrency, processOneRecord);

  const toDelete = [];
  for (const r of perRecord) {
    if (r && r.delete && r.receiptHandle) toDelete.push(r.receiptHandle);
  }

  await deleteBatch(QUEUE_URL, toDelete);

  // SQS/Lambda will treat partial failures by retrying the entire batch unless using batchItemFailures.
  // Provide batchItemFailures so only failed items are retried (higher throughput).
  const batchItemFailures = [];
  for (let i = 0; i < records.length; i++) {
    const rec = records[i];
    const res = perRecord[i];
    if (!res || !res.ok) batchItemFailures.push({ itemIdentifier: rec.messageId });
  }

  return { batchItemFailures };
};